import{_ as e,o,c as p,ak as l}from"./chunks/framework.aEAtsvX-.js";const m=JSON.parse('{"title":"领地","description":"","frontmatter":{},"headers":[],"relativePath":"plugins/lands.md","filePath":"plugins/lands.md","lastUpdated":1776470952000}'),c={name:"plugins/lands.md"};function s(t,a,d,n,r,i){return o(),p("div",null,[...a[0]||(a[0]=[l('<h1 id="领地" tabindex="-1">领地 <a class="header-anchor" href="#领地" aria-label="Permalink to “领地”">​</a></h1><div class="tip custom-block"><p class="custom-block-title">提示</p><p><strong>推荐使用GUI进行一些比较复杂的操作。</strong> 使用<code>/cd</code>打开GUI界面。</p></div><p>使用<code>/lands menu main</code>进入领土菜单。 使用<code>/lands help</code>可以帮助你掌握这个插件的用法。</p><h2 id="领地和家的区别" tabindex="-1">领地和家的区别 <a class="header-anchor" href="#领地和家的区别" aria-label="Permalink to “领地和家的区别”">​</a></h2><p>家的本质是一个传送点，可以让你传送到一个地方。 领土就是俗称的“圈地”，领土可以保护你的方块不受破坏。</p><h2 id="领地相关的限制" tabindex="-1">领地相关的限制 <a class="header-anchor" href="#领地相关的限制" aria-label="Permalink to “领地相关的限制”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">提示</p><p><strong>赞助服务器可以提升这些限制。</strong></p><p>玩家可以同时加入6个不同的领土。</p><p>玩家可以同时拥有2个领土。</p><p>每个领土花钱认领区块上限48个。</p><p>每个玩家加入领土增加16个领土认领区块上限。</p><p>每个领土可以有18名玩家,包括所有者。</p><p>每个领土有8个领土子区域(每个区域可以独立设置)。</p><p>每个领土可以设置9个玩家身份角色(用于玩家加入领土时的权限)。</p><p>每个领土/国家可以设置3个敌对领土。</p><p>每个领土/国家可以设置6个盟友。</p><p>每个国家可以由8个领土组成。</p></div><h2 id="创建领地" tabindex="-1">创建领地 <a class="header-anchor" href="#创建领地" aria-label="Permalink to “创建领地”">​</a></h2><p><code>/lands create [领土名称]</code></p><blockquote><p>领土是永久存在的（一个周目内）。</p></blockquote><blockquote><p>领土和国家需缴纳维护费，服务器定期收取，国家级领土需承担所合并领土的总维护费。玩家加入领土既能提升规模上限、降低维护费，也可提高区块认领上限。最高级领土可升级为国家，通过邀请其他领土加入以提升国家级别。</p></blockquote><h2 id="创建营地" tabindex="-1">创建营地 <a class="header-anchor" href="#创建营地" aria-label="Permalink to “创建营地”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">警告</p><p>营地是临时领土，过一段时间会自动被删除。</p></div><p><code>/lands createcamp [名称]</code></p><h2 id="其他命令" tabindex="-1">其他命令 <a class="header-anchor" href="#其他命令" aria-label="Permalink to “其他命令”">​</a></h2><p><strong>这些命令基本可以在菜单中实现。</strong></p><p><code>/lands map</code> 用GUI认领区块。</p><p><code>/lands viem</code> 用粒子效果显示自己或他人领土的范围。</p><p><code>/lands unclaim</code> 取消认领所站的区块，会退还一定的游戏币。</p>',19)])])}const b=e(c,[["render",s]]);export{m as __pageData,b as default};
